example_bad:
fn main() {
    let mut s = String::from("hello");
    let r = &s;
    let s2 = s; // Error: cannot move out of `s` because it is borrowed
    println!("{}", r);
}

fixes.code:
let mut s = String::from("hello");
{
    let r = &s;
    println!("{}", r);
} // r goes out of scope here
let s2 = s; // Now this works

let s = String::from("hello");
let r = &s;
let s2 = s.clone();
println!("{}", r); // Works!
